export default TOOLS.map((t) => {
  const props = t.props.map((p) => ({ icon: p[0], h: p[1], body: p[2] }));
  const sections = [
    {
      h: `How the Ardovo + ${t.tool} integration works`,
      body: t.how,
      bullets: t.flows,
    },
  ];
  if (t.also) sections.push(t.also);
  const setup = t.setup || [
    ['Connect in one click', `Open Ardovo Settings, go to Integrations, find ${t.tool}, and click Connect. Authorize the connection with OAuth or an API key.`],
    ['Choose what syncs', `Pick which records and events sync between Ardovo and ${t.tool}, and set the direction to one-way or two-way.`],
    ['Map your fields', `Match ${t.tool} fields to Ardovo fields once. Rook suggests the mapping so most teams accept the defaults and move on.`],
    ['Turn it on', `Rook backfills recent history, then keeps both sides current. You can pause, edit, or audit the sync anytime.`],
  ];
  const faqs = t.faqs.map(([q, a]) => ({ q, a }));
  faqs.push({
    q: `How do I connect ${t.tool} to Ardovo, and is it secure?`,
    a: `Open Ardovo Settings, go to Integrations, find ${t.tool}, and click Connect. Authorize with OAuth or an API key, choose what syncs and in which direction, and Rook backfills history and keeps both sides current. Setup takes minutes, needs no code, and every change is written to the Ardovo audit log.`,
  });
  return {
    slug: `rally-${t.slug}-integration`,
    type: 'integration',
    title: `Ardovo + ${t.tool} Integration`,
    metaTitle: `Ardovo + ${t.tool} Integration: Two-Way Sync and Setup (2026) | Ardovo`,
    metaDescription: t.meta,
    eyebrow: `Ardovo + ${t.tool}`,
    h1: `Ardovo + ${t.tool} integration`,
    shortAnswer: t.short,
    intro: [
      `Connect Ardovo to ${t.tool} so your ${t.category.toLowerCase()} work and your revenue data stay in one place. ${t.introLine}`,
    ],
    stats: [
      { value: 'Minutes', label: 'Time to connect' },
      { value: 'Two-way', label: 'Sync direction' },
      { value: 'No code', label: 'Setup effort' },
    ],
    valuePropsHeading: `What flows between Ardovo and ${t.tool}`,
    valueProps: props,
    sections,
    stepsHeading: `Setting up the Ardovo + ${t.tool} integration`,
    steps: setup.map(([h, body]) => ({ h, body })),
    faqs,
    published: '2026-07-10',
    updated: '2026-07-10',
  };
});
